sql:
SELECT share_percentage
FROM market_shares
WHERE commodity_id = 0 AND share_date = '2023-01-01';

SELECT commodity_id, AVG(trade_volume) AS average_trade_volume
FROM trading_partner_commodities
GROUP BY commodity_id;

SELECT COUNT(*) 
FROM trading_partners 
WHERE partner_type = 'supplier';

SELECT SUM(trade_volume) AS total_trade_volume
FROM trading_partner_commodities
WHERE commodity_id = 1;

SELECT trade_volume
FROM trading_partner_commodities
WHERE commodity_id = 1 AND partner_id = 1;

SELECT SUM(production_capacity) AS total_production_capacity
FROM production_site_commodities
WHERE site_id = 1;

SELECT commodity_name 
FROM commodities 
WHERE commodity_id = 0;
